// Paradigm/Zone lookups built from lib/paradigms.json (definitions) +
// lib/talk-paradigms.json (per-talk classifications, generated by parallel
// subagent classification — see /tmp/tp-classify/ pipeline).
//
// Graceful fallback: if talk-paradigms.json is missing or empty, this module
// returns empty zone lists and the UI can render a "classification pending" state.

import type { Talk, ActId } from "./types";
import { TALKS } from "./talks";
import paradigmsRaw from "./paradigms.json";

export interface ParadigmDef {
  id: string;
  name: string;
  blurb: string;
  seedZones: string[];
}

export const PARADIGMS: Record<string, ParadigmDef> = paradigmsRaw as Record<string, ParadigmDef>;
export const PARADIGM_ORDER: string[] = [
  "privacy", "identity", "markets", "scaling", "consensus",
  "cryptography", "builders-craft", "governance", "ai-agents", "real-world",
];

interface TalkParadigmEntry {
  paradigms: string[];
  zone: string;
  threadIds: string[];
}

// Lazy-load the classification artifact. Returns {} if missing.
let _talkParadigms: Record<string, TalkParadigmEntry> | null = null;
function loadTalkParadigms(): Record<string, TalkParadigmEntry> {
  if (_talkParadigms !== null) return _talkParadigms;
  try {
    // Static import would fail at build if file absent. Use require so missing → empty.
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const data = require("./talk-paradigms.json") as Record<string, TalkParadigmEntry>;
    _talkParadigms = data || {};
  } catch {
    _talkParadigms = {};
  }
  return _talkParadigms;
}

export interface Zone {
  id: string;            // canonical slug
  name: string;          // canonical display name
  paradigm: string;      // paradigm id
  talks: Talk[];         // ordered by tier then year asc
}

export interface ParadigmInAct {
  paradigm: ParadigmDef;
  zones: Zone[];
  totalTalks: number;
}

const TIER_RANK: Record<string, number> = { boss: 0, main: 1, side: 2, chronicle: 3 };
const DEVCON_YEARS = [2014, 2015, 2016, 2017, 2018, 2019, 2022, 2023, 2024];

function yearOf(t: Talk): number {
  const m = (t.event || "").match(/(20\d{2})/);
  if (m) return parseInt(m[1], 10);
  if (t.source === "devcon" && t.ed >= 0 && t.ed < DEVCON_YEARS.length) return DEVCON_YEARS[t.ed];
  return 0;
}

function slugifyZone(name: string): string {
  return name.toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9\s-]/g, "")
    .trim()
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-");
}

