// Generic zone names that should NOT route — fall through to talk's primary paradigm.
const GENERIC_ZONES = new Set([
  "sponsor workshop", "sponsor demo", "workshop", "workshops",
  "ceremony", "ecosystem talk", "ecosystem panel", "panel",
  "lightning", "music", "keynote", "intro", "introduction",
  "fireside", "ama", "demo", "demos", "talks", "misc",
  "general", "other", "various", "multi-topic", "default",
]);

// Sorted synonym keys (longest first) — for substring fallback matching.
const SORTED_SYNONYM_KEYS: string[] = Object.keys(ZONE_SYNONYMS).sort((a, b) => b.length - a.length);

function routeZone(rawZone: string, talkParadigms: string[]): ZoneRoute | null {
  const norm = rawZone.trim().toLowerCase().replace(/\s+/g, " ");
  if (!norm || GENERIC_ZONES.has(norm)) {
    if (talkParadigms.length === 0) return null;
    return null; // generic name + only talkParadigm context — drop, don't pollute
  }
  if (ZONE_SYNONYMS[norm]) return ZONE_SYNONYMS[norm];
  for (const k of SORTED_SYNONYM_KEYS) {
    if (k.length < 4) continue;
    if (norm.includes(k)) return ZONE_SYNONYMS[k];
  }
  if (talkParadigms.length === 0) return null;
  // No synonym — keep zone in talk's primary paradigm with its original name.
  return { paradigm: talkParadigms[0], canonicalName: rawZone.trim() };
}

// Build per-Act paradigm view. Cached after first call.
const _cache: Record<ActId, ParadigmInAct[]> = {} as Record<ActId, ParadigmInAct[]>;
let _built = false;

function build() {
  if (_built) return;
  _built = true;
  const tp = loadTalkParadigms();
  const acts: ActId[] = ["I", "II", "III", "IV", "V", "VI"];

  // Per-Act → paradigmId → zoneName → Talk[]
  const perAct: Record<ActId, Record<string, Map<string, Talk[]>>> = {} as Record<ActId, Record<string, Map<string, Talk[]>>>;
  for (const a of acts) perAct[a] = {};

  for (const t of TALKS) {
    const entry = tp[t.id];
    if (!entry || !entry.paradigms || entry.paradigms.length === 0) continue;
    const route = routeZone(entry.zone || "", entry.paradigms);
    if (!route) continue;
    if (!PARADIGMS[route.paradigm]) continue;
    const actBucket = perAct[t.act as ActId];
    if (!actBucket) continue;
    if (!actBucket[route.paradigm]) actBucket[route.paradigm] = new Map();
    const zones = actBucket[route.paradigm];
    if (!zones.has(route.canonicalName)) zones.set(route.canonicalName, []);
    zones.get(route.canonicalName)!.push(t);
  }

  for (const actId of acts) {
    const out: ParadigmInAct[] = [];
    const actBucket = perAct[actId];
    for (const pid of PARADIGM_ORDER) {
      const paradigm = PARADIGMS[pid];
      if (!paradigm) continue;
      const zoneMap = actBucket[pid];
      if (!zoneMap || zoneMap.size === 0) continue;

      const zones: Zone[] = [];
      for (const [name, talks] of zoneMap) {
        talks.sort((a, b) => {
          const tr = (TIER_RANK[a.tier] ?? 9) - (TIER_RANK[b.tier] ?? 9);
          if (tr !== 0) return tr;
          return yearOf(a) - yearOf(b);
        });
        zones.push({
          id: `${pid}--${slugifyZone(name)}`,
          name,
          paradigm: pid,
          talks,
        });
      }
      zones.sort((a, b) => b.talks.length - a.talks.length || a.name.localeCompare(b.name));
      out.push({
        paradigm,
        zones,
        totalTalks: zones.reduce((n, z) => n + z.talks.length, 0),
      });
    }
    out.sort((a, b) => b.totalTalks - a.totalTalks);
    _cache[actId] = out;
  }
}

export function getParadigmsInAct(actId: ActId): ParadigmInAct[] {
  build();
  return _cache[actId] || [];
}

export function getEffectiveThreadIdsFromParadigms(): Record<string, string[]> {
  // For lib/auto-threads.ts to merge LLM-suggested threadIds.
  const tp = loadTalkParadigms();
  const out: Record<string, string[]> = {};
  for (const [talkId, entry] of Object.entries(tp)) {
    if (entry.threadIds && entry.threadIds.length > 0) out[talkId] = entry.threadIds;
  }
  return out;
}

export function isClassificationLoaded(): boolean {
  return Object.keys(loadTalkParadigms()).length > 0;
}
